mapper.select:
SELECT
    *
FROM data_info
WHERE submitter_id = #{submitterId}
  AND task_id = #{taskId}
  AND version = #{version}

SELECT d.*
FROM data_info d
JOIN (
    SELECT submitter_id, MAX(submit_time) AS max_upload_time
    FROM data_info
    WHERE task_id = #{taskId}
    GROUP BY submitter_id
) AS latest
ON d.submitter_id = latest.submitter_id AND d.submit_time = latest.max_upload_time
WHERE d.task_id = #{taskId}
